import { PlusOutlined } from '@ant-design/icons';
import { Button, message, Modal, Typography, Breadcrumb } from 'antd';
import React, { useState, useRef, Fragment } from 'react';
import { PageContainer } from '@ant-design/pro-layout';
import type { ProColumns, ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { ModalForm, ProFormSelect, ProFormText, ProFormTextArea } from '@ant-design/pro-form';
import { tokens, addToken, deleteToken } from '@/services/api';
import type { API } from '@/services/typings';
import { t, renderDetails, getTablePaginationConfig } from '../../../global';
import MyModalConfirm from '@/components/Others/MyModalConfirm';

const handleAdd = async (data: any) => {
  let device = data['devices'];
  let log = data['audits'];
  let user = data['users'];
  let user_group = data['user-groups'];
  let strategy = data['strategies'];
  let ab = data['ab'];
  let device_group = data['device-groups'];
  let admin_role = data['admin-roles'];
  let control_role = data['control-roles'];
  if (!device && !log && !user && !user_group && !strategy && !ab && !device_group && !admin_role && !control_role) {
    message.error(t('Please select at least one permission'));
    return;
  }
  const perms = {} as any;
  if (device) {
    perms['devices'] = device == 'Read-only' ? 'r' : 'rw';
  }
  if (log) {
    perms['audits'] = log == 'Read-only' ? 'r' : 'rw';
  }
  if (user) {
    perms['users'] = user == 'Read-only' ? 'r' : 'rw';
  }
  if (user_group) {
    perms['user-groups'] = user_group == 'Read-only' ? 'r' : 'rw';
  }
  if (strategy) {
    perms['strategies'] = strategy == 'Read-only' ? 'r' : 'rw';
  }
  if (ab) {
    perms['ab'] = ab == 'Read-only' ? 'r' : 'rw';
  }
  if (device_group) {
    perms['device-groups'] = device_group == 'Read-only' ? 'r' : 'rw';
  }
  if (admin_role) {
    perms['admin-roles'] = admin_role == 'Read-only' ? 'r' : 'rw';
  }
  if (control_role) {
    perms['control-roles'] = control_role == 'Read-only' ? 'r' : 'rw';
  }
  const new_data: API.TokenPayload = {
    name: data['name'] as string,
    perms,
  };
  if (data['desc']) {
    new_data['desc'] = data['desc'] as string;
  }

  const hide = message.loading(t('Adding'));
  try {
    const res = await addToken(new_data);
    hide();
    Modal.info({ title: "Token", content: <div><p>Make sure to copy this token now as you will not be able to see this again.</p><Typography.Text copyable code={true}>{res}</Typography.Text></div>, okText: "OK" });
    return res;
  } catch (error) {
    hide();
    message.error(
      typeof error == 'string' ? (error as string) : t('Adding failed, please try again!'),
    );
  }
  return;
};

const handleDelete = async (row: API.UserSession) => {
  const hide = message.loading(t('Deleting'));
  try {
    await deleteToken(row.id);
    hide();

    message.success(t('Deletion is successful'));
    return true;
  } catch (error) {
    hide();
    message.error(
      typeof error == 'string' ? (error as string) : t('Deletion failed, please try again!'),
    );
    return false;
  }
};

const TableList: React.FC = () => {
  const [createModalVisible, handleModalVisible] = useState<boolean>(false);
  const [showDetail, setShowDetail] = useState<boolean>(false);

  const actionRef = useRef<ActionType>();

  const [currentRow, setCurrentRow] = useState<API.UserSession>();

  const DeleteToken = (props: { children: any; onClick: () => void }) => (
    <MyModalConfirm
      title={t('deleteConfirm', true, 'Are you sure to delete?')}
      onConfirm={() => props.onClick()}
      okText="Yes"
      cancelText="No"
    >
      {props.children}
    </MyModalConfirm>
  );

  const newForm = (
    visible: boolean,
    onVisibleChange: React.Dispatch<React.SetStateAction<boolean>>,
    pActionRef: React.MutableRefObject<ActionType | undefined>,
  ) => {
    if (!visible) return null;
    return (
      <ModalForm
        title={t('Create')}
        visible={visible}
        width="400px"
        onVisibleChange={onVisibleChange}
        onFinish={async (value) => {
          const res = await handleAdd(
            value,
          );
          if (res) {
            if (pActionRef.current) {
              pActionRef.current.reload();
            }
          }
          handleModalVisible(false);
        }}
      >
        <ProFormText
          fieldProps={{ autoComplete: 'off' }}
          rules={[
            {
              required: true,
              whitespace: true,
            },
            {
              min: 4,
              max: 30,
            },
          ]}
          width="md"
          name="name"
          label={t('Name', true)}
        />
        <ProFormTextArea
          fieldProps={{ autoComplete: 'off' }}
          rules={[
            {
              max: 300,
            },
          ]}
          width="md"
          name="desc"
          label={t('Description', true)}
        />
        <ProFormSelect
          width="md"
          name="devices"
          label={t('Device Permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="users"
          label={t('User Permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="device-groups"
          label={t('device_group_permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="user-groups"
          label={t('user_group_permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="ab"
          label={t('Address Book Permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="audits"
          label={t('Audit Log Permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="strategies"
          label={t('Strategy Permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="admin-roles"
          label={t('Admin Role Permission', true)}
          options={['Read-only', 'Read and write']}
        />
        <ProFormSelect
          width="md"
          name="control-roles"
          label={t('Control Role Permission', true)}
          options={['Read-only', 'Read and write']}
        />
      </ModalForm>
    );
  };

  const columns: ProColumns<API.UserSession>[] = [
    {
      title: t('Name'),
      dataIndex: ['token', 'name'],
      search: false,
      render: (dom, entity) => {
        return (
          <a
            onClick={() => {
              setCurrentRow(entity);
              setShowDetail(true);
            }}
          >
            {dom}
          </a>
        );
      },
    },
    {
      title: t('Created Time'),
      dataIndex: 'created_at',
      valueType: 'dateTime',
      render: (text, record) => new Date((record.created_at || 0) * 1000).toLocaleString(),
      search: false,
    },
    {
      title: t('Permissions'),
      dataIndex: ['token', 'perms'],
      search: false,
      hideInTable: true,
      render: (text, record) => {
        const perms = record.token?.perms;
        return (
          <div>
            {perms?.devices && <p>{t('Devices')}: {perms?.devices == 'rw' ? t('Read and write') : t('Read-only')}</p>}
            {perms?.audits && <p>{t('Audits')}: {perms?.audits == 'rw' ? t('Read and write') : t('Read-only')}</p>}
            {perms?.users && <p>{t('Users')}: {perms?.users == 'rw' ? t('Read and write') : t('Read-only')}</p>}
            {perms?.['user-groups'] && <p>{t('User Groups')}: {perms?.['user-groups'] == 'rw' ? t('Read and write') : t('Read-only')}</p>}
            {perms?.strategies && <p>{t('Strategies')}: {perms?.strategies == 'rw' ? t('Read and write') : t('Read-only')}</p>}
            {perms?.['device-groups'] && <p>{t('Device Groups')}: {perms?.['device-groups'] == 'rw' ? t('Read and write') : t('Read-only')}</p>}
          </div>
        );
      },
    },
    {
      title: t('Description'),
      dataIndex: ['token', 'desc'],
      search: false,
    },
    {
      title: t('Action'),
      search: false,
      render: (text, record) => (
        <Fragment>
          <DeleteToken
            onClick={async () => {
              setCurrentRow(record);
              await handleDelete(record);
              actionRef.current?.reloadAndRest?.();
            }}
          >
            <a>{t('Delete')}</a>
          </DeleteToken>
        </Fragment>
      ),
    },
  ];

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.Settings', true) },
          { title: t('menu.Settings.Tokens', true) },
        ]} />
      )}
    >
      <ProTable<API.UserSession, API.PageParams>
        headerTitle={t('Token List')}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'tokenlist_columns_state' }}
        actionRef={actionRef}
        rowKey="id"
        search={false}
        rowSelection={false}
        toolBarRender={() => [
          <Button
            type="primary"
            key="primary"
            onClick={() => {
              handleModalVisible(true);
            }}
          >
            <PlusOutlined /> {t('Create')}
          </Button>,
        ]}
        request={async (params) => {
          try {
            const res = await tokens(params);
            const data = {
              data: res,
              success: true,
              total: res.length,
            };
            return data;
          } catch (error) {
            message.error(error as any);
            return {};
          }
        }}
        columns={columns}
        pagination={getTablePaginationConfig("token_list")}
      />
      {newForm(
        createModalVisible,
        handleModalVisible,
        actionRef,
      )}
      {renderDetails(
        showDetail,
        currentRow?.id,
        currentRow,
        columns.slice(0, columns.length - 1),
        setCurrentRow,
        setShowDetail,
      )}
    </PageContainer>
  );
};

export default TableList;
